class Solution {
    public String strWithout3a3b(int a, int b) {
        StringBuilder sb = new StringBuilder();
        char lastChar = '\0';
        int lastCount = 0;

        while (a > 0 || b > 0) {
            if (lastCount >= 2) {
                if (lastChar == 'a') {
                    if (b > 0) {
                        sb.append('b');
                        b--;
                        lastChar = 'b';
                        lastCount = 1;
                    }
                } else {
                    if (a > 0) {
                        sb.append('a');
                        a--;
                        lastChar = 'a';
                        lastCount = 1;
                    }
                }
            } else {
                if (a > b) {
                    sb.append('a');
                    a--;
                    lastChar = 'a';
                    lastCount++;
                } else {
                    sb.append('b');
                    b--;
                    lastChar = 'b';
                    lastCount++;
                }
            }
        }

        return sb.toString();
    }
}

